use std::collections::BinaryHeap;

fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    let m = m as usize;
    let n = n as usize;
    let INF: i64 = i64::MAX;
    let mut dist = vec![vec![vec![INF; 2]; n]; m];
    dist[0][0][1] = 1;

    let mut heap = BinaryHeap::new();
    heap.push((1, 0, 0, 1));

    let directions = [(0, 1), (1, 0)];

    while let Some((cost, i, j, parity)) = heap.pop() {
        if cost > dist[i][j][parity] {
            continue;
        }

        if i == m - 1 && j == n - 1 {
            return cost;
        }

        if parity == 1 {
            for (di, dj) in directions {
                let ni = i as i64 + di as i64;
                let nj = j as i64 + dj as i64;
                if ni >= 0 && ni < m as i64 && nj >= 0 && nj < n as i64 {
